package com.hospital.management.model;import java.util.*;/** Bill input excluding all derived financial fields. */public class BillForm{private Long billId,patientId,appointmentId;private String taxAmount,discountAmount,status;private List<BillItemForm>items=new ArrayList<>();public Long getBillId(){return billId;}public void setBillId(Long v){billId=v;}public Long getPatientId(){return patientId;}public void setPatientId(Long v){patientId=v;}public Long getAppointmentId(){return appointmentId;}public void setAppointmentId(Long v){appointmentId=v;}public String getTaxAmount(){return taxAmount;}public void setTaxAmount(String v){taxAmount=v;}public String getDiscountAmount(){return discountAmount;}public void setDiscountAmount(String v){discountAmount=v;}public String getStatus(){return status;}public void setStatus(String v){status=v;}public List<BillItemForm>getItems(){return items;}public void setItems(List<BillItemForm>v){items=v==null?new ArrayList<>():new ArrayList<>(v);}}
